import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.isRoot
import com.pinterest.ktlint.rule.engine.core.api.isWhiteSpace
import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment
import org.jetbrains.kotlin.com.intellij.psi.PsiWhiteSpace
import org.jetbrains.kotlin.psi.KtFile
import org.jetbrains.kotlin.psi.KtModifierListOwner
import org.jetbrains.kotlin.psi.KtPsiFactory
import org.jetbrains.kotlin.psi.psiUtil.endOffset
import org.jetbrains.kotlin.psi.psiUtil.startOffset

/**
 * Replaces deprecated ktlint-disable/ktlint-enable directives in comments with @Suppress annotations when possible.
 */
public class KtlintSuppressionDirectiveRule : StandardRule("ktlint-suppression") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (!node.isRoot()) {
            return
        }
        val psiFactory = KtPsiFactory(node.psi.project, true)
        val comments = mutableListOf<ASTNode>()
        val modifierListOwners = mutableListOf<KtModifierListOwner>()
        node.collect { astNode ->
            (astNode.psi as? PsiComment)?.let { comments.add(astNode) }
            (astNode.psi as? KtModifierListOwner)?.let { modifierListOwners.add(it) }
        }

        val sortedComments = comments.sortedBy { it.startOffset }
        val openBlockDirectives = mutableListOf<BlockDirective>()
        val handledComments = mutableSetOf<ASTNode>()

        for (commentNode in sortedComments) {
            if (commentNode in handledComments) {
                continue
            }
            val directive = commentNode.parseDirective() ?: continue
            when (commentNode.elementType) {
                EOL_COMMENT -> {
                    if (directive.type == DirectiveType.DISABLE) {
                        handleEolDirective(commentNode, directive, psiFactory, autoCorrect, emit)
                    } else {
                        emit(commentNode.startOffset, ERROR_MESSAGE, false)
                    }
                }

                BLOCK_COMMENT -> {
                    when (directive.type) {
                        DirectiveType.DISABLE -> openBlockDirectives.add(BlockDirective(commentNode, directive.ruleIds))
                        DirectiveType.ENABLE -> {
                            val openDirective =
                                openBlockDirectives.lastOrNull { it.ruleIds == directive.ruleIds }
                            if (openDirective == null) {
                                emit(commentNode.startOffset, ERROR_MESSAGE, false)
                            } else {
                                openBlockDirectives.remove(openDirective)
                                val handled =
                                    handleBlockDirective(
                                        openDirective,
                                        commentNode,
                                        modifierListOwners,
                                        psiFactory,
                                        autoCorrect,
                                        emit,
                                    )
                                if (handled) {
                                    handledComments.add(commentNode)
                                }
                            }
                        }
                    }
                }
            }
        }

        openBlockDirectives.forEach { openDirective ->
            val handled =
                handleOpenBlockDirective(
                    openDirective,
                    modifierListOwners,
                    node.psi as? KtFile,
                    psiFactory,
                    autoCorrect,
                    emit,
                )
            if (!handled) {
                emit(openDirective.node.startOffset, ERROR_MESSAGE, false)
            }
        }
    }

    private fun handleEolDirective(
        commentNode: ASTNode,
        directive: Directive,
        psiFactory: KtPsiFactory,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val target = commentNode.findModifierListOwnerTarget()
        emit(commentNode.startOffset, ERROR_MESSAGE, target != null)
        if (autoCorrect && target != null) {
            val annotationText = createAnnotationText(directive.ruleIds)
            target.addAnnotationEntry(psiFactory.createAnnotationEntry(annotationText))
            removeCommentNode(commentNode)
        }
    }

    private fun handleBlockDirective(
        openDirective: BlockDirective,
        closeNode: ASTNode,
        modifierListOwners: List<KtModifierListOwner>,
        psiFactory: KtPsiFactory,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ): Boolean {
        val candidate =
            modifierListOwners
                .filter { it.startOffset > openDirective.node.startOffset && it.endOffset < closeNode.startOffset }
                .singleOrNull()
        val canAutoCorrect =
            candidate != null &&
                !hasOtherCodeBetween(openDirective.node, closeNode, candidate.startOffset until candidate.endOffset)
        emit(openDirective.node.startOffset, ERROR_MESSAGE, canAutoCorrect)
        if (autoCorrect && canAutoCorrect && candidate != null) {
            val annotationText = createAnnotationText(openDirective.ruleIds)
            candidate.addAnnotationEntry(psiFactory.createAnnotationEntry(annotationText))
            removeCommentNode(openDirective.node)
            removeCommentNode(closeNode)
            return true
        }
        return false
    }

    private fun handleOpenBlockDirective(
        openDirective: BlockDirective,
        modifierListOwners: List<KtModifierListOwner>,
        ktFile: KtFile?,
        psiFactory: KtPsiFactory,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ): Boolean {
        val directiveNode = openDirective.node
        if (directiveNode.isTopOfFile() && ktFile != null) {
            val canAutoCorrect = true
            emit(directiveNode.startOffset, ERROR_MESSAGE, canAutoCorrect)
            if (autoCorrect) {
                val annotationText = createAnnotationText(openDirective.ruleIds).removePrefix("@")
                ktFile.addFileAnnotation(psiFactory, annotationText)
                removeCommentNode(directiveNode)
            }
            return true
        }

        val candidate =
            modifierListOwners
                .filter { it.startOffset > directiveNode.startOffset }
                .singleOrNull()
        if (candidate != null && !hasOtherCodeAfter(directiveNode, candidate.startOffset until candidate.endOffset)) {
            val canAutoCorrect = true
            emit(directiveNode.startOffset, ERROR_MESSAGE, canAutoCorrect)
            if (autoCorrect) {
                val annotationText = createAnnotationText(openDirective.ruleIds)
                candidate.addAnnotationEntry(psiFactory.createAnnotationEntry(annotationText))
                removeCommentNode(directiveNode)
            }
            return true
        }
        emit(directiveNode.startOffset, ERROR_MESSAGE, false)
        return false
    }

    private fun KtFile.addFileAnnotation(
        psiFactory: KtPsiFactory,
        annotationText: String,
    ) {
        val fileAnnotationList = fileAnnotationList
        val annotationEntry = psiFactory.createFileAnnotation(annotationText)
        if (fileAnnotationList == null) {
            val newAnnotationList = psiFactory.createFileAnnotationListWithAnnotation(annotationText)
            val anchor = firstChild
            addBefore(newAnnotationList, anchor)
            addBefore(psiFactory.createWhiteSpace("\n"), anchor)
        } else {
            val lastEntry = fileAnnotationList.annotationEntries.lastOrNull()
            if (lastEntry == null) {
                fileAnnotationList.add(annotationEntry)
            } else {
                val newLine = psiFactory.createWhiteSpace("\n")
                fileAnnotationList.addAfter(newLine, lastEntry)
                fileAnnotationList.addAfter(annotationEntry, newLine)
            }
        }
    }

    private fun createAnnotationText(ruleIds: List<String>): String {
        val annotationArguments =
            if (ruleIds.isEmpty()) {
                listOf(ALL_RULES_ARGUMENT)
            } else {
                ruleIds.map { "ktlint:${normalizeRuleId(it)}" }
            }.distinct()
        val arguments = annotationArguments.joinToString(", ") { "\"$it\"" }
        return "@Suppress($arguments)"
    }

    private fun normalizeRuleId(ruleId: String): String =
        if (ruleId.startsWith(EXPERIMENTAL_RULE_SET_PREFIX)) {
            "${STANDARD_RULE_SET_PREFIX}${ruleId.removePrefix(EXPERIMENTAL_RULE_SET_PREFIX)}"
        } else {
            ruleId
        }

    private fun ASTNode.findModifierListOwnerTarget(): KtModifierListOwner? {
        val prevLeaf = prevLeaf { !it.isWhiteSpace() && it.psi !is PsiComment }
        val prevPsi = prevLeaf?.psi ?: return null
        var parent = prevPsi
        while (parent != null) {
            if (parent is KtModifierListOwner) {
                return parent
            }
            parent = parent.parent
        }
        return null
    }

    private fun ASTNode.isTopOfFile(): Boolean =
        prevLeaf { !it.isWhiteSpace() && it.psi !is PsiComment } == null

    private fun hasOtherCodeBetween(
        startNode: ASTNode,
        endNode: ASTNode,
        allowedRange: IntRange,
    ): Boolean {
        var hasOtherCode = false
        startNode.treeParent.collect { node ->
            if (!node.isLeaf()) {
                return@collect
            }
            if (node.startOffset <= startNode.startOffset || node.startOffset >= endNode.startOffset) {
                return@collect
            }
            if (node.startOffset in allowedRange) {
                return@collect
            }
            if (!node.isWhiteSpace() && node.psi !is PsiComment) {
                hasOtherCode = true
            }
        }
        return hasOtherCode
    }

    private fun hasOtherCodeAfter(
        startNode: ASTNode,
        allowedRange: IntRange,
    ): Boolean {
        var hasOtherCode = false
        startNode.treeParent.collect { node ->
            if (!node.isLeaf()) {
                return@collect
            }
            if (node.startOffset <= startNode.startOffset) {
                return@collect
            }
            if (node.startOffset in allowedRange) {
                return@collect
            }
            if (!node.isWhiteSpace() && node.psi !is PsiComment) {
                hasOtherCode = true
            }
        }
        return hasOtherCode
    }

    private fun ASTNode.collect(block: (ASTNode) -> Unit) {
        block(this)
        getChildren(null).forEach { it.collect(block) }
    }

    private fun ASTNode.isLeaf() = getChildren(null).isEmpty()

    private fun removeCommentNode(commentNode: ASTNode) {
        (commentNode.treePrev as? PsiWhiteSpace)
            ?.takeIf { !it.textContains('\n') }
            ?.let { it.parent?.node?.removeChild(it.node) }
        commentNode.treeParent.removeChild(commentNode)
    }

    private fun ASTNode.parseDirective(): Directive? {
        val trimmedText =
            if (elementType == EOL_COMMENT) {
                text.removePrefix("//")
            } else {
                text.removePrefix("/*").removeSuffix("*/")
            }
                .trim()
        val parts = trimmedText.split(Regex("\\s+")).filter { it.isNotBlank() }
        if (parts.isEmpty()) {
            return null
        }
        val type =
            when (parts[0]) {
                DISABLE_DIRECTIVE -> DirectiveType.DISABLE
                ENABLE_DIRECTIVE -> DirectiveType.ENABLE
                else -> return null
            }
        return Directive(type, parts.drop(1))
    }

    private data class BlockDirective(
        val node: ASTNode,
        val ruleIds: List<String>,
    )

    private data class Directive(
        val type: DirectiveType,
        val ruleIds: List<String>,
    )

    private enum class DirectiveType {
        DISABLE,
        ENABLE,
    }

    private companion object {
        const val ERROR_MESSAGE = "Replace ktlint suppression directives with @Suppress annotations"
        const val DISABLE_DIRECTIVE = "ktlint-disable"
        const val ENABLE_DIRECTIVE = "ktlint-enable"
        const val ALL_RULES_ARGUMENT = "ktlint"
        const val EXPERIMENTAL_RULE_SET_PREFIX = "experimental:"
        const val STANDARD_RULE_SET_PREFIX = "standard:"
    }
}

public val KTLINT_SUPPRESSION_RULE_ID: RuleId = KtlintSuppressionDirectiveRule().ruleId
