 23→/**
 24→ * Ensures annotations occur immediately prior to the annotated construct
 25→ *
 26→ * https://kotlinlang.org/docs/reference/coding-conventions.html#annotation-formatting
 27→ */
 28→public class AnnotationSpacingRule : StandardRule("annotation-spacing") {
 29→    private companion object {
 30→        const val ERROR_MESSAGE = "Annotations should occur immediately before the annotated construct"
 31→    }
 32→
 33→    override fun beforeVisitChildNodes(
 34→        node: ASTNode,
 35→        autoCorrect: Boolean,
 36→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 37→    ) {
 38→        if (node.elementType != ElementType.MODIFIER_LIST && node.elementType != ElementType.FILE_ANNOTATION_LIST) {
 39→            return
 40→        }
 41→
 42→        val annotations =
 43→            node.children()
 44→                .mapNotNull { it.psi as? KtAnnotationEntry }
 45→                .toList()
 46→        if (annotations.isEmpty()) {
 47→            return
 48→        }
 49→
 50→        // Join the nodes that immediately follow the annotations (whitespace), then add the final whitespace
 51→        // if it's not a child of root. This happens when a new line separates the annotations from the annotated
 52→        // construct. In the following example, there are no whitespace children of root, but root's next sibling is the
 53→        // new line whitespace.
 54→        //
 55→        //      @JvmField
 56→        //      val s: Any
 57→        //
 58→        val whiteSpaces =
 59→            (annotations.asSequence().map { it.nextSibling } + node.treeNext)
 60→                .filterIsInstance<PsiWhiteSpace>()
 61→                .take(annotations.size)
 62→                .toList()
 63→
 64→        val next =
 65→            node.nextSiblingWithAtLeastOneOf(
 66→                {
 67→                    !it.isWhiteSpace() &&
 68→                        it.textLength > 0 &&
 69→                        !it.isPartOf(ElementType.FILE_ANNOTATION_LIST) &&
 70→                        !it.isCommentOnSameLineAsPrevLeaf()
 71→                },
 72→                {
 73→                    // Disallow multiple white spaces as well as comments
 74→                    if (it.psi is PsiWhiteSpace) {
 75→                        val s = it.text
 76→                        // Ensure at least one occurrence of two line breaks
 77→                        s.indexOf("\n") != s.lastIndexOf("\n")
 78→                    } else {
 79→                        it.isPartOfComment() && !it.isCommentOnSameLineAsPrevLeaf()
 80→                    }
 81→                },
 82→            )
 83→        if (next != null) {
 84→            if (node.elementType != ElementType.FILE_ANNOTATION_LIST && next.isPartOfComment()) {
 85→                val psi = node.psi
 86→                emit(psi.endOffset, ERROR_MESSAGE, true)
 87→                if (autoCorrect) {
 88→                    // Special-case autocorrection when the annotation is separated from the annotated construct
 89→                    // by a comment: we need to swap the order of the comment and the annotation
 90→                    // Remove the annotation and the following whitespace
 91→                    val eolComment = node.nextSibling { it.isCommentOnSameLineAsPrevLeaf() }
 92→                    if (eolComment != null) {
 93→                        eolComment.prevSibling { it.isWhiteSpace() }?.let { it.treeParent.removeChild(it) }
 94→                        eolComment.nextSibling { it.isWhiteSpace() }?.let { it.treeParent.removeChild(it) }
 95→                        eolComment.treeParent?.removeChild(eolComment)
 96→                    } else {
 97→                        node.nextSibling { it.isWhiteSpace() }?.let { it.treeParent?.removeChild(it) }
 98→                    }
 99→                    node.treeParent.removeChild(node)
100→
101→                    // Insert the annotation prior to the annotated construct
102→                    val beforeAnchor = next.nextCodeSibling()
103→                    val treeParent = next.treeParent
104→                    treeParent.addChild(node, beforeAnchor)
105→                    if (eolComment != null) {
106→                        treeParent.addChild(PsiWhiteSpaceImpl(" "), beforeAnchor)
107→                        treeParent.addChild(eolComment, beforeAnchor)
108→                    }
109→                    treeParent.addChild(PsiWhiteSpaceImpl("\n"), beforeAnchor)
110→                }
111→            }
112→        }
113→        if (whiteSpaces.isNotEmpty() && node.elementType != ElementType.FILE_ANNOTATION_LIST) {
114→            // Check to make sure there are multi breaks between annotations
115→            if (whiteSpaces.any { psi -> psi.textToCharArray().count { it == '\n' } > 1 }) {
116→                val psi = node.psi
117→                emit(psi.endOffset, ERROR_MESSAGE, true)
118→                if (autoCorrect) {
119→                    removeIntraLineBreaks(node, annotations.last())
120→                    removeExtraLineBreaks(node)
121→                }
122→            }
123→        }
124→    }
125→
126→    private inline fun ASTNode.nextSiblingWithAtLeastOneOf(
127→        p: (ASTNode) -> Boolean,
128→        needsToOccur: (ASTNode) -> Boolean,
129→    ): ASTNode? {
130→        var n = this.treeNext
131→        var occurrenceCount = 0
132→        while (n != null) {
133→            if (needsToOccur(n)) {
134→                occurrenceCount++
135→            }
136→            if (p(n)) {
137→                return if (occurrenceCount > 0) {
138→                    n
139→                } else {
140→                    null
141→                }
142→            }
143→            n = n.treeNext
144→        }
145→        return null
146→    }
147→
148→    private fun removeExtraLineBreaks(node: ASTNode) {
149→        val next =
150→            node.nextSibling {
151→                it.isWhiteSpaceWithNewline()
152→            } as? LeafPsiElement
153→        if (next != null) {
154→            rawReplaceExtraLineBreaks(next)
155→        }
156→    }
157→
158→    private fun rawReplaceExtraLineBreaks(leaf: LeafPsiElement) {
159→        // Replace the extra white space with a single break
160→        val text = leaf.text
161→        val firstIndex = text.indexOf("\n") + 1
162→        val replacementText =
163→            text.substring(0, firstIndex) +
164→                text.substringAfter("\n").replace("\n", "")
165→
166→        leaf.rawReplaceWithText(replacementText)
167→    }
168→
169→    private fun removeIntraLineBreaks(
170→        node: ASTNode,
171→        last: KtAnnotationEntry,
172→    ) {
173→        val txt = node.text
174→        // Pull the next before raw replace or it will blow up
175→        val lNext = node.nextLeaf()
176→        if (node is PsiWhiteSpaceImpl) {
177→            if (txt.toCharArray().count { it == '\n' } > 1) {
178→                rawReplaceExtraLineBreaks(node)
179→            }
180→        }
181→
182→        if (lNext != null && !last.text.endsWith(lNext.text)) {
183→            removeIntraLineBreaks(lNext, last)
184→        }
185→    }
